const resumeProfile = {
  name: 'Nikhil',
  currentTitle: 'Fresher - Computer Science Engineer',
  experienceYears: 0,
  skills: [
    'React', 'JavaScript', 'HTML', 'CSS', 'Tailwind CSS',
    'Node.js', 'Spring Boot', 'REST APIs',
    'MongoDB', 'MySQL',
    'Java', 'Python',
    'Git', 'Postman',
    'Machine Learning', 'NLP', 'RAG', 'LLM'
  ],
  preferredRoles: [
    'Junior Frontend Developer',
    'Junior Full Stack Developer',
    'React Developer Fresher',
    'Junior Java Developer',
    'Software Engineer Fresher',
    'Graduate Software Engineer'
  ],
  locations: ['Hyderabad', 'Bangalore', 'Remote']
};

const searchQueries = [];

for (const role of resumeProfile.preferredRoles) {
  for (const loc of resumeProfile.locations) {
    searchQueries.push({
      query: role + ' ' + loc,
      role: role,
      location: loc,
      skills: resumeProfile.skills,
      resumeSummary: 'Fresher B.Tech CSE (AI & ML) graduate with hands-on project experience in React, Spring Boot, Node.js, MongoDB, MySQL. Built 3 full-stack projects including a coding platform, e-commerce site, and movie booking system. AI/ML knowledge including NLP and RAG. Looking for entry-level software developer roles.'
    });
  }
}

return searchQueries.map(function(q) {
  return { json: q };
});

const items = [];

for (const item of $input.all()) {
  const data = item.json;

  // Handle SerpAPI response
  if (data.jobs_results && Array.isArray(data.jobs_results)) {
    for (const job of data.jobs_results) {
      items.push({
        title: job.title || 'No Title',
        company: job.company_name || 'Unknown',
        location: job.location || 'Not specified',
        description: job.description || '',
        link: job.share_link || '',
        source: 'Google Jobs',
        postedAt: job.detected_extensions?.posted_at || 'Recent',
        jobId: job.job_id || job.title + job.company_name
      });
    }
  }

  // Handle Naukri/Apify response (array of jobs)
  if (Array.isArray(data)) {
    for (const job of data) {
      items.push({
        title: job.title || 'No Title',
        company: job.companyName || job.company || 'Unknown',
        location: job.location || 'Not specified',
        description: job.jobDescription || job.description || '',
        link: job.jdURL || job.url || '',
        source: 'Naukri',
        postedAt: job.createdDate || 'Recent',
        jobId: job.jobId || job.jdURL || job.title
      });
    }
  }

  // Handle single Naukri job object
  if (data.title && data.jdURL) {
    items.push({
      title: data.title || 'No Title',
      company: data.companyName || 'Unknown',
      location: data.location || 'Not specified',
      description: data.jobDescription || '',
      link: data.jdURL || '',
      source: 'Naukri',
      postedAt: data.createdDate || 'Recent',
      jobId: data.jobId || data.jdURL
    });
  }
}

// Deduplicate by jobId
const seen = new Set();
const unique = items.filter(function(job) {
  if (!job.jobId || seen.has(job.jobId)) return false;
  seen.add(job.jobId);
  return true;
});

if (unique.length === 0) {
  return [{ json: { error: 'No jobs found', raw: $input.all()[0]?.json } }];
}

return unique.map(function(job) {
  return { json: job };
});

const items = [];

for (const item of $input.all()) {
  const job = item.json;

  // Skip if no title
  if (!job.title) continue;

  // Hyderabad filter
  const locationLower = (job.location || '').toLowerCase();
  const titleLower = (job.title || '').toLowerCase();
  const descLower = (job.description || '').toLowerCase();

  const isHyderabad = locationLower.includes('hyderabad')
    || locationLower.includes('telangana')
    || locationLower.includes('secunderabad')
    || locationLower.includes('remote');

  // Skip if not Hyderabad or Remote
  if (!isHyderabad) continue;

  const title = job.title || 'Job Opening';
  const company = job.company || 'Unknown Company';
  const location = job.location || 'Not specified';
  const source = job.source || '';
  const postedAt = job.postedAt || 'Recent';
  const link = job.link || '';

  let message = '';

  if (link) {
    message = '💼 ' + title + '\n'
      + '🏢 ' + company + '\n'
      + '📍 ' + location + '\n'
      + '🌐 ' + source + '\n'
      + '📅 ' + postedAt + '\n\n'
      + '🔗 Apply: ' + link;
  } else {
    message = '💼 ' + title + '\n'
      + '🏢 ' + company + '\n'
      + '📍 ' + location + '\n'
      + '🌐 ' + source + '\n'
      + '📅 ' + postedAt + '\n\n'
      + '🔗 No direct link available';
  }

  items.push({ json: { message: message } });
}

if (items.length === 0) {
  return [{ json: { message: '⚠️ No Hyderabad fresher jobs found this run.' } }];
}

return items;

const fresherKeywords = [
  'fresher', 'fresh', 'entry level', 'entry-level',
  'junior', '0-1', '0-2', '0 year', '0 to 1', '0 to 2',
  'graduate', 'trainee', 'intern', 'internship',
  'no experience', 'recent graduate', '2024', '2025', '2026',
  'beginner', 'newly', 'new grad', 'campus', 'college hire',
  'just graduated', '0 years', 'less than 1'
];

const seniorKeywords = [
  'senior', 'sr.', 'lead', 'manager', 'architect',
  'principal', 'director', 'head of', 'vp ', 'vice president',
  '3+ years', '4+ years', '5+ years', '6+ years',
  '7+ years', '8+ years', '10+ years',
  '3 years', '4 years', '5 years', '6 years',
  '7 years', '8 years', '10 years'
];

const items = [];

for (const item of $input.all()) {
  const job = item.json;

  // Skip jobs with no title
  if (!job.title) continue;

  const titleLower = (job.title || '').toLowerCase();
  const descLower = (job.description || '').toLowerCase();
  const combined = titleLower + ' ' + descLower;

  // Block senior roles
  const isSenior = seniorKeywords.some(k => combined.includes(k.toLowerCase()));
  if (isSenior) continue;

  // Check if fresher friendly in title
  const isFresherTitle = fresherKeywords.some(k => titleLower.includes(k.toLowerCase()));

  // Check if fresher friendly in description
  const isFresherDesc = fresherKeywords.some(k => descLower.includes(k.toLowerCase()));

  // Allow if experience is 0-2 years mentioned
  const hasLowExp = /0[\s-]*(to)?[\s-]*[12]\s*year/i.test(combined);

  // Allow if no experience requirement mentioned at all
  const noExpMentioned = !combined.includes('year') && !combined.includes('experience');

  if (isFresherTitle || isFresherDesc || hasLowExp || noExpMentioned) {
    items.push({ json: job });
  }
}

if (items.length === 0) {
  return [{
    json: {
      title: 'No Jobs Found',
      company: '',
      location: '',
      source: '',
      postedAt: '',
      link: '',
      message: '⚠️ No fresher jobs found this run. Will check again in 3 hours.'
    }
  }];
}

return items;
